// Email parser — maps Built In / Wellfound / LinkedIn alert emails to job objects
const source_map = {
  'builtin.com': 'builtin',
  'wellfound.com': 'wellfound',
  'linkedin.com': 'linkedin',
};

function detectSource(from, subject) {
  const combined = `${from} ${subject}`.toLowerCase();
  for (const [domain, source] of Object.entries(source_map)) {
    if (combined.includes(domain)) return source;
  }
  return 'email_unknown';
}

function extractLinksAndText(html) {
  const results = [];
  const linkRe = /<a[^>]+href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi;
  let m;
  while ((m = linkRe.exec(html)) !== null) {
    results.push({ href: m[1], text: m[2].replace(/<[^>]+>/g, '').trim() });
  }
  return results;
}

function parseBuiltIn(html) {
  const jobs = [];
  const links = extractLinksAndText(html);
  for (const link of links) {
    if (!link.href.includes('builtin.com/job') && !link.href.includes('builtin.com/jobs')) continue;
    if (!link.text || link.text.length < 3) continue;
    jobs.push({ source: 'builtin', title: link.text, company: null, location: null, url: link.href.split('?')[0], salary_min: null, salary_max: null, employment_type: 'unknown', description: null, posted_at: null });
  }
  return jobs;
}

function parseWellfound(html) {
  const jobs = [];
  const links = extractLinksAndText(html);
  for (const link of links) {
    if (!link.href.includes('wellfound.com/jobs') && !link.href.includes('angel.co/job')) continue;
    if (!link.text || link.text.length < 3) continue;
    jobs.push({ source: 'wellfound', title: link.text, company: null, location: null, url: link.href.split('?')[0], salary_min: null, salary_max: null, employment_type: 'unknown', description: null, posted_at: null });
  }
  return jobs;
}

function parseLinkedIn(html) {
  const jobs = [];
  const links = extractLinksAndText(html);
  for (const link of links) {
    if (!link.href.includes('linkedin.com/jobs/view') && !link.href.includes('linkedin.com/comm/jobs')) continue;
    if (!link.text || link.text.length < 3) continue;
    jobs.push({ source: 'linkedin', title: link.text, company: null, location: null, url: link.href.split('?')[0], salary_min: null, salary_max: null, employment_type: 'unknown', description: null, posted_at: null });
  }
  return jobs;
}

const crypto = require('crypto');
function makeJobId(source, title, url) {
  const raw = `${source}:${(title || "").toLowerCase()}:${(url || "").slice(-40)}`;
  return crypto.createHash('md5').update(raw).digest('hex');
}

const output = [];
for (const item of items) {
  const email = item.json;
  const html = email.body || email.html || email.snippet || "";
  const from = email.from || "";
  const subject = email.subject || "";
  const source = detectSource(from, subject);

  let rawJobs = [];
  if (source === 'builtin') rawJobs = parseBuiltIn(html);
  else if (source === 'wellfound') rawJobs = parseWellfound(html);
  else if (source === 'linkedin') rawJobs = parseLinkedIn(html);

  const parsed = rawJobs.map(job => ({
    json: {
      ...job,
      job_id: makeJobId(job.source, job.title, job.url),
      raw_json: { email_subject: subject, email_from: from },
    }
  }));

  if (parsed.length > 0) output.push(...parsed);
}

return output.length > 0 ? output : [{ json: { _skip: true } }];

// Job scoring logic
const FILTERS = {
  minSalary: 170000,
  targetSalary: 200000,
  contractKeywords: ["contract", "c2c", "corp-to-corp", "1099", "w2 only", "w2 contract", "6-month", "12-month", "temp"],
  agencyKeywords: ["staffing", "recruiting", "talent", "solutions llc", "consulting group", "resources inc", "workforce"],
  fteKeywords: ["full-time", "full time", "permanent", "fte", "direct hire"],
  seniorKeywords: ["staff ", "principal", "senior", "sr.", "lead", "head of", "director"],
  juniorKeywords: ["junior", "entry level", "associate", "intern", "graduate"],
  contractIncludeThreshold: 60,
  fteIncludeThreshold: 40,
};

function containsAny(text, keywords) {
  if (!text) return false;
  const lower = text.toLowerCase();
  return keywords.some(k => lower.includes(k));
}

function scoreJob(job) {
  let score = 50;
  let flaggedContract = false;
  const titleAndDesc = `${job.title || ""} ${job.description || ""}`;
  const companyName = job.company || "";

  const salMin = job.salary_min || 0;
  const salMax = job.salary_max || 0;
  const salRef = salMax || salMin;

  if (salRef > 0 && salRef < FILTERS.minSalary) return { score: 0, flaggedContract: false, include: false, excludeReason: "salary_too_low" };
  if (salRef >= FILTERS.targetSalary) score += 10;
  else if (salRef >= FILTERS.minSalary) score += 5;

  const isFTE = job.employment_type === "fulltime" || containsAny(titleAndDesc, FILTERS.fteKeywords);
  if (isFTE) score += 20;

  const isContractTitle = containsAny(titleAndDesc, FILTERS.contractKeywords);
  const isAgency = containsAny(companyName, FILTERS.agencyKeywords);
  if (isContractTitle || isAgency) {
    score -= (isContractTitle ? 30 : 0) + (isAgency ? 20 : 0);
    flaggedContract = true;
  }

  if (containsAny(job.title, FILTERS.seniorKeywords)) score += 15;
  if (containsAny(job.title, FILTERS.juniorKeywords)) score -= 20;
  if (containsAny(titleAndDesc, ["equity", "rsu", "stock options", "espp"])) score += 10;

  const threshold = flaggedContract ? FILTERS.contractIncludeThreshold : FILTERS.fteIncludeThreshold;
  const include = score >= threshold;
  return { score, flaggedContract, include, excludeReason: include ? null : "score_below_threshold" };
}

const output = [];
for (const item of items) {
  const job = item.json;
  const result = scoreJob(job);
  if (result.include) {
    output.push({
      json: {
        ...job,
        score: result.score,
        flagged_contract: result.flaggedContract,
      }
    });
  }
}
return output;

// Discord formatter
const WEBHOOK_BATCH_SIZE = 10;

function formatSalary(min, max) {
  if (!min && !max) return "Salary not listed";
  const fmt = (n) => `$${Math.round(n / 1000)}k`;
  if (min && max && min !== max) return `${fmt(min)}\u2013${fmt(max)}`;
  return fmt(min || max);
}

function jobEmbed(job) {
  const fte = job.flagged_contract;
  const emoji = fte ? "\uD83D\uDFE1" : "\uD83D\uDFE2";
  const tag = fte ? "[CONTRACT \u26A0\uFE0F]" : "[FTE]";
  const sourceLabel = (job.source || "unknown").toUpperCase();
  const salary = formatSalary(job.salary_min, job.salary_max);
  const location = job.location || "Location not listed";
  return {
    title: `${emoji} ${tag} ${job.title} \u2014 ${job.company || "Unknown Company"}`,
    url: job.url || "",
    color: fte ? 0xFFA500 : 0x00C853,
    fields: [
      { name: "\uD83D\uDCCD Location", value: location, inline: true },
      { name: "\uD83D\uDCB0 Salary", value: salary, inline: true },
      { name: "\uD83D\uDD17 Source", value: sourceLabel, inline: true },
      { name: "\u2B50 Score", value: String(job.score), inline: true },
    ],
    footer: { text: fte ? "Flagged: contract/C2C \u2014 included on merit" : "FTE" },
  };
}

const allJobs = items[0].json.data || items.map(i => i.json);

const batches = [];
for (let i = 0; i < allJobs.length; i += WEBHOOK_BATCH_SIZE) {
  batches.push(allJobs.slice(i, i + WEBHOOK_BATCH_SIZE));
}

const output = [];
const fteCount = allJobs.filter(j => !j.flagged_contract).length;
const contractCount = allJobs.filter(j => j.flagged_contract).length;
output.push({
  json: {
    content: `\uD83D\uDCCB **Daily Job Digest** \u2014 ${allJobs.length} new jobs (${fteCount} FTE, ${contractCount} contract)`,
    embeds: []
  }
});

for (const batch of batches) {
  output.push({
    json: {
      content: "",
      embeds: batch.map(job => jobEmbed(job))
    }
  });
}
return output;
